fields.calculatedFormula:
DATE (
    /*YEAR*/
    YEAR (  TODAY()  ) - FLOOR(  18   / 12) - IF (MONTH (   TODAY()   ) - MOD(  18  , 12) > 0, 0, 1),

    /*MONTH*/ 
    IF (MONTH (  TODAY()  ) - MOD ( 18 , 12) > 0, MONTH (  TODAY()  ) - MOD ( 18 , 12), MONTH (  TODAY()  ) - MOD ( 18 , 12) + 12),

    /*DAY*/ 
    MIN (DAY (  TODAY()  ), 
        CASE (

   /* Month */     
   IF (MONTH (  TODAY()  ) - MOD ( 18 , 12) > 0, MONTH (  TODAY()  ) - MOD ( 18 , 12), MONTH (  TODAY()  ) - MOD ( 18 , 12) + 12), 9, 30, 4, 30, 6, 30, 11, 30, 2, 

   /* return max days for February dependent on if end date is leap year */ 
   IF (MOD (YEAR (  TODAY()  ) - FLOOR( 18 / 12) - IF (MONTH (  TODAY()  ) - MOD( 18 , 12) > 0, 0, 1), 400) = 0 || (MOD (YEAR (  TODAY()  ) - FLOOR( 18 / 12) - IF (MONTH (  TODAY()  ) - MOD( 18 , 12) > 0, 0, 1) ,4) = 0 && MOD (YEAR (  TODAY()  ) - FLOOR( 18 / 12) - IF (MONTH (  TODAY()  ) - MOD( 18 , 12) > 0, 0, 1) ,100) <> 0 ), 29, 28), 31)
    )
)

